from collections import deque

def calculate_degree_centrality(graph):
    centralities = {}
    num_nodes = len(graph)

    if num_nodes <= 1:
        for node in graph:
            centralities[node] = 0.0
        return centralities

    for node in graph:
        degree = len(graph[node])
        centralities[node] = degree / (num_nodes - 1)
    return centralities

def calculate_betweenness_centrality(graph):
    centralities = {node: 0.0 for node in graph}
    num_nodes = len(graph)

    if num_nodes <= 2:
        return centralities

    for s in graph:
        S = []
        P = {node: [] for node in graph}
        sigma = {node: 0 for node in graph}
        d = {node: -1 for node in graph}

        sigma[s] = 1
        d[s] = 0
        Q = deque([s])

        while Q:
            v = Q.popleft()
            S.append(v)

            for w in graph[v]:
                if d[w] < 0:
                    d[w] = d[v] + 1
                    Q.append(w)
                if d[w] == d[v] + 1:
                    sigma[w] += sigma[v]
                    P[w].append(v)

        delta = {node: 0.0 for node in graph}

        while S:
            w = S.pop()
            for v in P[w]:
                delta[v] += (sigma[v] / sigma[w]) * (1 + delta[w])

            if w != s:
                centralities[w] += delta[w]

    normalization_factor = (num_nodes - 1) * (num_nodes - 2) / 2.0
    for node in centralities:
        centralities[node] /= normalization_factor

    return centralities
